// TestNamespaceScopedEvaluation tests that evaluations are scoped to namespaces
func TestNamespaceScopedEvaluation(t *testing.T) {
	testStore := setupTestDatabase(t)
	defer testStore.Shutdown(context.Background())

	ctx := context.Background()
	store, err := storagesql.New(testStore.DB)
	require.NoError(t, err)

	// Create two namespaces
	_, err = store.CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
		Key: "namespace-1",
	})
	require.NoError(t, err)

	_, err = store.CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
		Key: "namespace-2",
	})
	require.NoError(t, err)

	// Create flag in namespace-1
	_, err = store.CreateFlag(ctx, &flipt.CreateFlagRequest{
		NamespaceKey: "namespace-1",
		Key:          "shared-flag",
		Name:         "Shared Flag",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      true,
	})
	require.NoError(t, err)

	// Create flag in namespace-2 with different name
	_, err = store.CreateFlag(ctx, &flipt.CreateFlagRequest{
		NamespaceKey: "namespace-2",
		Key:          "shared-flag",
		Name:         "Different Flag",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      false,
	})
	require.NoError(t, err)

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	server := evaluation.New(logger, store)

	// Create HTTP server
	mux := http.NewServeMux()
	registerEvaluationHandlers(mux, server)
	ts := httptest.NewServer(mux)
	defer ts.Close()

	// Evaluate in namespace-1
	req1 := rpcevaluation.EvaluationRequest{
		NamespaceKey: "namespace-1",
		FlagKey:      "shared-flag",
		EntityId:     "user-123",
	}
	data1, err := protojson.Marshal(&req1)
	require.NoError(t, err)

	resp1, err := http.Post(ts.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(data1))
	require.NoError(t, err)
	defer resp1.Body.Close()

	body1, err := io.ReadAll(resp1.Body)
	require.NoError(t, err)

	var result1 rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body1, &result1)
	require.NoError(t, err)

	// Evaluate in namespace-2
	req2 := rpcevaluation.EvaluationRequest{
		NamespaceKey: "namespace-2",
		FlagKey:      "shared-flag",
		EntityId:     "user-123",
	}
	data2, err := protojson.Marshal(&req2)
	require.NoError(t, err)

	resp2, err := http.Post(ts.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(data2))
	require.NoError(t, err)
	defer resp2.Body.Close()

	body2, err := io.ReadAll(resp2.Body)
	require.NoError(t, err)

	var result2 rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body2, &result2)
	require.NoError(t, err)

	// Assert different results for same flag key in different namespaces
	assert.True(t, result1.Enabled)
	assert.False(t, result2.Enabled)
}

