// TestBatchEvaluationSuccess tests batch evaluation with multiple requests
func TestBatchEvaluationSuccess(t *testing.T) {
	testStore := setupTestDatabase(t)
	defer testStore.Shutdown(context.Background())

	ctx := context.Background()
	store, err := storagesql.New(testStore.DB)
	require.NoError(t, err)

	// Create namespace
	_, err = store.CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
		Key: "default",
	})
	require.NoError(t, err)

	// Create boolean flag
	_, err = store.CreateFlag(ctx, &flipt.CreateFlagRequest{
		NamespaceKey: "default",
		Key:          "flag-1",
		Name:         "Flag 1",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      true,
	})
	require.NoError(t, err)

	// Create variant flag
	_, err = store.CreateFlag(ctx, &flipt.CreateFlagRequest{
		NamespaceKey: "default",
		Key:          "flag-2",
		Name:         "Flag 2",
		Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		Enabled:      true,
	})
	require.NoError(t, err)

	// Create a variant
	_, err = store.CreateVariant(ctx, &flipt.CreateVariantRequest{
		NamespaceKey: "default",
		FlagKey:      "flag-2",
		Key:          "variant-a",
		Name:         "Variant A",
	})
	require.NoError(t, err)

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	server := evaluation.New(logger, store)

	// Create HTTP server
	mux := http.NewServeMux()
	registerEvaluationHandlers(mux, server)
	ts := httptest.NewServer(mux)
	defer ts.Close()

	// Make batch request
	batchReq := rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-1",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				NamespaceKey: "default",
				FlagKey:      "flag-1",
				EntityId:     "user-1",
			},
			{
				NamespaceKey: "default",
				FlagKey:      "flag-2",
				EntityId:     "user-1",
			},
		},
	}

	batchData, err := protojson.Marshal(&batchReq)
	require.NoError(t, err)

	resp, err := http.Post(
		ts.URL+"/evaluate/v1/batch",
		"application/json",
		bytes.NewReader(batchData),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	require.Equal(t, http.StatusOK, resp.StatusCode)

	respData, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var batchResp rpcevaluation.BatchEvaluationResponse
	err = protojson.Unmarshal(respData, &batchResp)
	require.NoError(t, err)

	// Assert we have responses for both requests
	assert.Len(t, batchResp.Responses, 2)

	// First response should be boolean
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)
	boolResp := batchResp.Responses[0].GetBooleanResponse()
	require.NotNil(t, boolResp)
	assert.True(t, boolResp.Enabled)
	assert.Equal(t, "flag-1", boolResp.FlagKey)

	// Second response should be variant
	assert.Equal(t, rpcevaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type)
	variantResp := batchResp.Responses[1].GetVariantResponse()
	require.NotNil(t, variantResp)
	assert.Equal(t, "flag-2", variantResp.FlagKey)
}

