	// Create HTTP server
	mux := http.NewServeMux()
	registerEvaluationHandlers(mux, server)
	ts := httptest.NewServer(mux)
	defer ts.Close()

	// Make batch request
	batchReq := rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-1",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				NamespaceKey: "default",
				FlagKey:      "flag-1",
				EntityId:     "user-1",
			},
			{
				NamespaceKey: "default",
				FlagKey:      "flag-2",
				EntityId:     "user-1",
			},
		},
	}

	batchData, err := protojson.Marshal(&batchReq)
	require.NoError(t, err)

	resp, err := http.Post(
		ts.URL+"/evaluate/v1/batch",
		"application/json",
		bytes.NewReader(batchData),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

